#!/usr/bin/env node

const urserviceHelper = require("./lib/urservice-helper");

function parseArguments() {
  const args = process.argv.slice(2);
  const vendorId = args[0];
  const urcapId = args[1];
  return { vendorId, urcapId };
}

const { vendorId, urcapId } = parseArguments();

(async () => {
  try {
    const msg = await urserviceHelper.deleteUrcap(vendorId, urcapId);
    console.log(msg);
  } catch (err) {
    console.error(`Failed to delete URCap:`);
    console.error(`\tMessage: ${err.message}`);
    console.error(`\tDetails: ${err.details}`);
  }
})();
